// Write a program to print whether a number is even or odd, also take input from the user.import java.util.*;public class CheckEvenOdd{    public static void main(String[] args){        Scanner sc=new Scanner(System.in);        int a=sc.nextInt();        if(a%2==0){            System.out.println(a+ " is even.");        }        else{            System.out.println(a + "is Odd.");        }    }}